async function checkDesktopTemplate() {
  const desktopPath = join(ROOT, "packaging", "omarchy", "codex-app-port.desktop");
  const launcherPath = join(ROOT, "scripts", "desktop-launcher.mjs");
  const content = await readFile(desktopPath, "utf8");
  const launcher = await readFile(launcherPath, "utf8");
  const iconPath = join(ROOT, "assets", "app-icon.svg");
  const icon = await readFile(iconPath, "utf8");
  if (!content.includes("Type=Application")) {
    throw new Error("desktop template is missing Type=Application");
  }
  if (!content.includes("Exec=node /opt/codex-app-port/scripts/desktop-launcher.mjs")) {
    throw new Error("desktop template Exec does not use the safe launcher path");
  }
  if (!content.includes("Icon=/opt/codex-app-port/assets/app-icon.svg")) {
    throw new Error("desktop template Icon does not use the packaged local icon");
  }
  if (/MimeType=/.test(content)) {
    throw new Error("desktop template must not register URL handlers yet");
  }
  if (!icon.includes("<svg") || !icon.includes("Codex App Port")) {
    throw new Error("application icon asset is missing expected SVG metadata");
  }
  if (
    !launcher.includes("createApprovalAuditLog") ||
    !launcher.includes("createActionAuditLog") ||
    !launcher.includes("buildDesktopServerOptions")
  ) {
    throw new Error("desktop launcher does not wire persistent sanitized audit logs");
  }
  pass("desktop template uses safe launcher, local icon, audit logs, and no URL handler");
}

async function checkUrlHandlerValidation() {
  const accepted = await runJsonCommand(
    process.execPath,
    ["scripts/url-handler.mjs", "--json", "codex-app-port://thread/b0153f06?workspace=default"],
    "url handler validation",
  );
  if (accepted.ok !== true || accepted.accepted !== false) {
    throw new Error("url handler did not validate in blocked mode");
  }
  if (
    accepted.capabilities?.opensBrowser !== false ||
    accepted.capabilities?.startsServer !== false ||
    accepted.capabilities?.appServerTraffic !== false ||
    accepted.capabilities?.commandExecution !== false ||
    accepted.policy?.registeredInDesktopEntry !== false
  ) {
    throw new Error("url handler validation unexpectedly enabled behavior");
  }

  const rejected = await runJsonCommand(
    process.execPath,
    ["scripts/url-handler.mjs", "--json", "codex://auth?code=secret"],
    "url handler unsupported scheme",
    { expectFailure: true },
  );
  if (rejected.ok !== false || rejected.code !== "unsupported-scheme") {
    throw new Error("url handler did not reject the unsupported codex scheme");
  }
  if (JSON.stringify(rejected).includes("secret")) {
    throw new Error("url handler rejection leaked sensitive query data");
  }
  const opened = await runJsonCommand(
    process.execPath,
    [
      "scripts/url-handler.mjs",
      "--json",
      "--open",
      "--origin",
      "http://127.0.0.1:14570/",
      "codex-app-port://thread/b0153f06?workspace=default",
    ],
    "url handler registered open",
    {
      env: {
        ...process.env,
        CODEX_APP_PORT_OPENER: "/bin/true",
      },
    },
  );
  if (
    opened.accepted !== true ||
    opened.opened !== true ||
    opened.capabilities?.opensBrowser !== true ||
    opened.capabilities?.startsServer !== false ||
    opened.capabilities?.appServerTraffic !== false ||
    opened.policy?.officialCodexSchemeRegistered !== false ||
    opened.localUiUrl !== "http://127.0.0.1:14570/#thread=b0153f06&workspace=default"
  ) {
    throw new Error("url handler registered mode did not preserve local-only policy");
  }
  pass("url handler validates and opens only the local scheme");
}

async function checkLocalInstaller() {
  const home = await mkdtemp(join(tmpdir(), "codex-app-port-install-"));
  try {
    const dryRun = await runJsonCommand(
      process.execPath,
      ["scripts/install-local.mjs", "--dry-run", "--json", "--home", home],
      "local installer dry run",
    );
    assertSafeInstallResult(dryRun, { expectWritten: false, home });

    const installed = await runJsonCommand(
      process.execPath,
      ["scripts/install-local.mjs", "--json", "--home", home],
      "local installer",
    );
    assertSafeInstallResult(installed, { expectWritten: true, home });

    const installedWithHandler = await runJsonCommand(
      process.execPath,
      ["scripts/install-local.mjs", "--json", "--url-handler", "--home", home],
      "local installer with URL handler",
    );
    assertSafeInstallResult(installedWithHandler, {
      expectWritten: true,
      home,
      expectUrlHandler: true,
    });

    const launcher = await readFile(
      join(home, ".local", "share", "codex-app-port", "scripts", "desktop-launcher.mjs"),
      "utf8",
    );
    if (!launcher.includes("desktop launcher failed")) {
      throw new Error("local installer did not copy the desktop launcher");
    }
    const desktop = await readFile(
      join(home, ".local", "share", "applications", "codex-app-port.desktop"),
      "utf8",
    );
    assertSafeDesktopEntry(desktop, home);
    const handlerDesktop = await readFile(
      join(home, ".local", "share", "applications", "codex-app-port-url-handler.desktop"),
      "utf8",
    );
    assertSafeUrlHandlerDesktopEntry(handlerDesktop, home);
  } finally {
    await rm(home, { recursive: true, force: true });
  }
  pass("local installer is user-scoped and keeps desktop guardrails");
}

async function checkLocalPackager() {
  const outDir = await mkdtemp(join(tmpdir(), "codex-app-port-package-"));
  try {
    const dryRun = await runJsonCommand(
      process.execPath,
      ["scripts/package-local.mjs", "--dry-run", "--json", "--out-dir", outDir],
      "local packager dry run",
    );
    assertSafePackageResult(dryRun, { expectWritten: false, outDir });

    const packaged = await runJsonCommand(
      process.execPath,
      ["scripts/package-local.mjs", "--json", "--out-dir", outDir],
      "local packager",
    );
    assertSafePackageResult(packaged, { expectWritten: true, outDir });

    const checksum = await readFile(packaged.sha256Path, "utf8");
    if (!checksum.includes(packaged.sha256) || !checksum.includes(packaged.archiveFilename)) {
      throw new Error("local packager checksum file does not match result metadata");
    }
    const archiveInfo = await stat(packaged.archivePath);
    if (!archiveInfo.isFile() || archiveInfo.size === 0) {
      throw new Error("local packager archive was not written");
    }
  } finally {
    await rm(outDir, { recursive: true, force: true });
  }
  pass("local packager creates a guarded archive and checksum");
}

async function checkArchPackageRecipe() {
  const outDir = await mkdtemp(join(tmpdir(), "codex-app-port-arch-package-"));
  try {
    const packaged = await runJsonCommand(
      process.execPath,
      ["scripts/package-arch.mjs", "--json", "--out-dir", outDir],
      "Arch package recipe",
    );
    assertSafeArchPackageResult(packaged, { outDir });

    const pkgbuild = await readFile(packaged.pkgbuildPath, "utf8");
    for (const required of [
      "source=('codex-app-port-0.1.0.tar.gz')",
      `sha256sums=('${packaged.sha256}')`,
      "/opt/codex-app-port",
      "packaging/omarchy/codex-app-port.desktop",
    ]) {
      if (!pkgbuild.includes(required)) {
        throw new Error(`Arch package recipe is missing ${required}`);
      }
    }
    for (const forbidden of [
      "SKIP",
      "post_install",
      "pre_install",
      "install=",
      "curl",
      "wget",
      "sudo",
      "systemctl",
      "xdg-mime",
      "MimeType=",
    ]) {
      if (pkgbuild.includes(forbidden)) {
        throw new Error(`Arch package recipe includes forbidden marker ${forbidden}`);
      }
    }
    if (/source=\([^)]*(?:https?|ftp|ssh):\/\//.test(pkgbuild)) {
      throw new Error("Arch package recipe source must not fetch from the network");
    }
  } finally {
    await rm(outDir, { recursive: true, force: true });
  }
  pass("Arch package recipe is local-only and guarded");
}

async function checkGoalAudit() {
  const audit = await runJsonCommand(
    process.execPath,
    ["scripts/goal-audit.mjs", "--json"],
    "goal audit",
  );
  if (audit.complete !== false) {
    throw new Error("goal audit unexpectedly reported the full port complete");
  }
  const items = new Map((audit.items ?? []).map((item) => [item.id, item]));
  for (const [id, expectedStatus] of [
    ["security-threat-model", "met"],
    ["turn-start-fail-closed", "met"],
    ["local-user-installer", "met"],
    ["project-selection", "met"],
    ["local-threads", "met"],
    ["streamed-agent-output", "met"],
    ["thread-transcript", "met"],
    ["real-turn-start", "partial"],
    ["approval-decisions", "met"],
    ["diff-review", "met"],
    ["terminal-action-surfaces", "met"],
    ["git-worktree-workflows", "met"],
    ["package-icon-update-policy", "met"],
    ["url-handler", "met"],
    ["settings-auth-mcp-skills-plugins", "partial"],
    ["protocol-types", "met"],
  ]) {
    const item = items.get(id);
    if (!item || item.status !== expectedStatus) {
      throw new Error(`goal audit item ${id} expected ${expectedStatus} but got ${item?.status}`);
    }
  }
  pass("goal audit reports current completion gaps");
}

async function checkProtocolContracts() {
  const protocol = await readFile(join(ROOT, "src", "app-server", "protocol.mjs"), "utf8");
  for (const marker of [
    "APP_SERVER_METHODS",
    "normalizeThreadReadResponse",
    "normalizeNotification",
    "RAW_FILE_CHANGE_FIELDS",
  ]) {
    if (!protocol.includes(marker)) {
      throw new Error(`protocol contracts missing ${marker}`);
    }
  }
  const tests = await readFile(join(ROOT, "test", "protocol-contract.test.mjs"), "utf8");
  for (const marker of [
    "normalizeThreadReadResponse strips raw file-change payloads",
    "normalizeNotification keeps notification metadata without text payloads",
  ]) {
    if (!tests.includes(marker)) {
      throw new Error(`protocol contract tests missing ${marker}`);
    }
  }
  const manifest = JSON.parse(
    await readFile(join(ROOT, "src", "app-server", "generated-schemas", "manifest.json"), "utf8"),
  );
  if (
    manifest.generator !== "codex app-server generate-json-schema --experimental" ||
    manifest.schemaCount < 200
  ) {
    throw new Error("generated protocol schema manifest is missing or incomplete");
  }
  const clientRequest = await readFile(
    join(ROOT, "src", "app-server", "generated-schemas", "json", "ClientRequest.json"),
    "utf8",
  );
  const serverRequest = await readFile(
    join(ROOT, "src", "app-server", "generated-schemas", "json", "ServerRequest.json"),
    "utf8",
  );
  for (const marker of [
    "turn/start",
    "thread/loaded/list",
    ...integrationMethodNames(),
    ...terminalActionMethodNames(),
  ]) {
    if (!clientRequest.includes(marker)) {
      throw new Error(`generated client protocol schema missing ${marker}`);
    }
  }
  for (const marker of [
    "item/commandExecution/requestApproval",
    "item/fileChange/requestApproval",
    "item/permissions/requestApproval",
    ...serverRequestMethodNames(),
  ]) {
    if (!serverRequest.includes(marker)) {
      throw new Error(`generated server protocol schema missing ${marker}`);
    }
  }
  const serverNotification = await readFile(
    join(ROOT, "src", "app-server", "generated-schemas", "json", "ServerNotification.json"),
    "utf8",
  );
  for (const marker of serverNotificationMethodNames()) {
    if (!serverNotification.includes(marker)) {
      throw new Error(`generated server notification schema missing ${marker}`);
    }
  }
  pass("app-server protocol contracts include generated schema snapshot");
}

async function checkPackageManifest() {
  const pkg = JSON.parse(await readFile(join(ROOT, "package.json"), "utf8"));
  if (pkg.dependencies || pkg.devDependencies || pkg.optionalDependencies) {
    throw new Error("package.json must not declare runtime dependencies for the current prototype");
  }
  pass("package manifest has no dependency tree");
}

async function checkAscii() {
  const files = await projectTextFiles();
  for (const file of files) {
    const content = await readFile(file, "utf8");
    if (/[^\x00-\x7F]/.test(content)) {
      throw new Error(`Non-ASCII content found in ${relative(file)}`);
    }
  }
  pass("text files are ASCII");
}

async function checkForbiddenExecutablePatterns() {
  const files = [];
  for (const dir of EXECUTABLE_SCAN_DIRS) {
    files.push(...(await walk(join(ROOT, dir))));
  }

  for (const file of files.filter(isTextFile)) {
    const content = await readFile(file, "utf8");
    for (const { pattern, label } of FORBIDDEN_EXECUTABLE_PATTERNS) {
      if (pattern.test(content)) {
        throw new Error(`Forbidden executable pattern ${label} found in ${relative(file)}`);
      }
    }
  }
  pass("no forbidden executable patterns");
}

async function checkSyntax() {
  const files = (await projectTextFiles()).filter((file) => /\.(?:mjs|js)$/.test(file));
  for (const file of files) {
    await runCommand(process.execPath, ["--check", file], `syntax ${relative(file)}`, {
      quiet: true,
    });
  }
  pass("JavaScript syntax checks pass");
}

