async function checkThreadSearchApi() {
  let searchCalled = false;
  const disabledServer = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    threadSearchFn: async () => {
      searchCalled = true;
      return { ok: true };
    },
  });
  const disabledPort = await listenWithFallback(disabledServer, {
    host: "127.0.0.1",
    port: 0,
  });
  const disabledBaseUrl = `http://127.0.0.1:${disabledPort}`;
  try {
    const token = await readUiSessionToken(disabledBaseUrl);
    const wrongMethod = await fetch(`${disabledBaseUrl}/api/thread-search`, {
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`thread search GET returned HTTP ${wrongMethod.status}`);
    }

    const response = await fetch(`${disabledBaseUrl}/api/thread-search`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "default",
        searchTerm: "private verify search query",
        archived: false,
      }),
    });
    if (response.status !== 403) {
      throw new Error(`disabled thread search returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    if (
      payload.appServer?.touched !== false ||
      payload.threadSearch?.enabled !== false ||
      payload.threadSearch?.searchTermAccepted !== false ||
      payload.threadSearch?.searchTermReturned !== false ||
      payload.threadSearch?.snippetsReturned !== false ||
      payload.threadSearch?.pathsReturned !== false ||
      payload.policy?.browserMethodCallsAccepted !== false ||
      searchCalled
    ) {
      throw new Error("disabled thread search did not preserve the blocked no-traffic policy");
    }
    if (
      serialized.includes("private verify search query") ||
      serialized.includes("/tmp/codex-app-port-verify")
    ) {
      throw new Error("disabled thread search leaked search term or workspace path");
    }

    const pathResponse = await fetch(`${disabledBaseUrl}/api/thread-search`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "/tmp/codex-app-port-verify",
        searchTerm: "private verify search query",
        archived: false,
      }),
    });
    if (pathResponse.status !== 404 || searchCalled) {
      throw new Error("thread search accepted a browser-provided workspace path");
    }
  } finally {
    await closeServer(disabledServer);
  }

  const calls = [];
  const enabledServer = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    threadSearchEnabled: true,
    threadSearchFn: async (options) => {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-06-29T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        initialize: {
          platformOs: "linux",
          platformFamily: "unix",
        },
        probes: {
          threadSearch: {
            method: "thread/search",
            searchTermCharCount: options.searchTerm.length,
            searchTermLineCount: 1,
            count: 1,
            returnedCount: 1,
            hasNextCursor: true,
            hasBackwardsCursor: true,
            archivedFilter: options.archived,
            snippetCount: 1,
            threadNameCount: 1,
            previewCount: 1,
            cwdBasenameCount: 1,
            items: [
              {
                idSuffix: "abcd1234",
                archived: options.archived,
                hasSnippet: true,
                hasName: true,
                hasPreview: true,
                status: "completed",
                source: "cli",
                modelProvider: "openai",
                createdAt: 1,
                updatedAt: 2,
                cwdBasename: "codex-app-port-verify",
                hasGitInfo: true,
              },
            ],
            searchTermReturned: true,
            snippetsReturned: true,
            namesReturned: true,
            previewsReturned: true,
            fullIdsReturned: true,
            pathsReturned: true,
            cursorsReturned: true,
            rawPayloadReturned: true,
            privateSnippet: "private verify search snippet",
            privatePath: "/tmp/codex-app-port-verify/private-search",
            privateCursor: "private-verify-search-cursor",
          },
        },
        notifications: {
          "remoteControl/status/changed": 1,
        },
      };
    },
  });
  const enabledPort = await listenWithFallback(enabledServer, {
    host: "127.0.0.1",
    port: 0,
  });
  const enabledBaseUrl = `http://127.0.0.1:${enabledPort}`;
  try {
    const token = await readUiSessionToken(enabledBaseUrl);
    const response = await fetch(`${enabledBaseUrl}/api/thread-search`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "default",
        searchTerm: "private verify search query",
        archived: true,
      }),
    });
    if (!response.ok) {
      throw new Error(`enabled thread search returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    if (
      calls.length !== 1 ||
      calls[0].searchTerm !== "private verify search query" ||
      calls[0].archived !== true ||
      payload.appServer?.touched !== true ||
      payload.threadSearch?.enabled !== true ||
      payload.threadSearch?.searchTermAccepted !== true ||
      payload.threadSearch?.items?.[0]?.idSuffix !== "abcd1234" ||
      payload.threadSearch?.searchTermReturned !== false ||
      payload.threadSearch?.snippetsReturned !== false ||
      payload.threadSearch?.namesReturned !== false ||
      payload.threadSearch?.previewsReturned !== false ||
      payload.threadSearch?.fullIdsReturned !== false ||
      payload.threadSearch?.pathsReturned !== false ||
      payload.threadSearch?.cursorsReturned !== false ||
      payload.threadSearch?.rawPayloadReturned !== false ||
      payload.policy?.browserMethodCallsAccepted !== true
    ) {
      throw new Error("enabled thread search did not return the sanitized opt-in shape");
    }
    for (const forbidden of [
      "private verify search query",
      "private verify search snippet",
      "private-verify-search-cursor",
      "/tmp/codex-app-port-verify",
      "searchTermReturned\":true",
      "snippetsReturned\":true",
      "pathsReturned\":true",
      "rawPayloadReturned\":true",
    ]) {
      if (serialized.includes(forbidden)) {
        throw new Error(`enabled thread search leaked ${forbidden}`);
      }
    }
  } finally {
    await closeServer(enabledServer);
  }

  pass("thread search is blocked by default and suffix/count-only when explicitly enabled");
}

async function checkDevServerApi() {
  const server = createDevServer({
    cwd: ROOT,
    workspaceInputs: ["/tmp"],
    threadLimit: 3,
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const unauthenticated = await fetch(`${baseUrl}/api/workspaces`);
    if (unauthenticated.status !== 403) {
      throw new Error(`dev server workspaces API without token returned HTTP ${unauthenticated.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const workspacesResponse = await fetch(`${baseUrl}/api/workspaces`, {
      headers: apiHeaders(token),
    });
    if (!workspacesResponse.ok) {
      throw new Error(`dev server workspaces API returned HTTP ${workspacesResponse.status}`);
    }
    assertSanitizedWorkspaces(await workspacesResponse.json(), {
      forbiddenPaths: [ROOT, ROOT.replace(/\/$/, "")],
    });

    const response = await fetch(`${baseUrl}/api/status`, {
      headers: apiHeaders(token),
    });
    if (!response.ok) {
      throw new Error(`dev server API returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    assertSanitizedStatus(payload, {
      forbidCodexBin: true,
      forbiddenPaths: [ROOT, ROOT.replace(/\/$/, "")],
    });
  } finally {
    await closeServer(server);
  }
  pass("dev server API returns sanitized read-only status");
}

