async function checkGitWorktreeApi() {
  const workspace = await mkdtemp(join(tmpdir(), "codex-app-port-verify-git-"));
  await mkdir(join(workspace, ".git", "worktrees", "linked-one"), { recursive: true });
  await mkdir(join(workspace, ".git", "refs", "heads", "feature"), { recursive: true });
  await writeFile(join(workspace, ".git", "HEAD"), "ref: refs/heads/feature/verify\n", "utf8");
  await writeFile(
    join(workspace, ".git", "refs", "heads", "feature", "verify"),
    "dddddddddddddddddddddddddddddddddddddddd\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "packed-refs"),
    "eeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee refs/heads/release/verify\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "worktrees", "linked-one", "HEAD"),
    "ref: refs/heads/release/linked\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "config"),
    '[remote "origin"]\n\turl = git@example.test:private/repo.git\n',
    "utf8",
  );
  await writeFile(join(workspace, "clean.txt"), "clean", "utf8");
  await writeFile(join(workspace, "modified.txt"), "changed", "utf8");
  await writeFile(join(workspace, "untracked.txt"), "local", "utf8");
  await writeGitIndex(join(workspace, ".git", "index"), [
    await gitIndexEntry(workspace, "clean.txt"),
    { path: "modified.txt", size: 1, mtimeSeconds: 1 },
    { path: "missing.txt", size: 7, mtimeSeconds: 1 },
  ]);

  let probeCalled = false;
  const server = createDevServer({
    cwd: workspace,
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/git-worktree`);
    if (withoutToken.status !== 403) {
      throw new Error(`git worktree API without token returned HTTP ${withoutToken.status}`);
    }

    const branchWithoutToken = await fetch(`${baseUrl}/api/git-branch-preflight`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ branch: "release/verify" }),
    });
    if (branchWithoutToken.status !== 403) {
      throw new Error(`git branch preflight without token returned HTTP ${branchWithoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/git-worktree`, {
      method: "POST",
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`git worktree POST returned HTTP ${wrongMethod.status}`);
    }

    const response = await fetch(`${baseUrl}/api/git-worktree`, {
      headers: apiHeaders(token),
    });
    if (!response.ok) {
      throw new Error(`git worktree API returned HTTP ${response.status}`);
    }
    assertSanitizedGitWorktree(await response.json(), { workspace });

    const branchWrongMethod = await fetch(`${baseUrl}/api/git-branch-preflight`, {
      headers: apiHeaders(token),
    });
    if (branchWrongMethod.status !== 405) {
      throw new Error(`git branch preflight GET returned HTTP ${branchWrongMethod.status}`);
    }

    const branchResponse = await fetch(`${baseUrl}/api/git-branch-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "default",
        branch: "release/verify",
      }),
    });
    if (!branchResponse.ok) {
      throw new Error(`git branch preflight returned HTTP ${branchResponse.status}`);
    }
    assertSanitizedGitBranchPreflight(await branchResponse.json(), { workspace });

    const unknownBranch = await fetch(`${baseUrl}/api/git-branch-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        branch: "private/secret-branch",
      }),
    });
    if (unknownBranch.status !== 404) {
      throw new Error(`unknown git branch preflight returned HTTP ${unknownBranch.status}`);
    }
    if ((await unknownBranch.text()).includes("private/secret-branch")) {
      throw new Error("unknown git branch preflight leaked the requested branch");
    }

    const invalid = await fetch(`${baseUrl}/api/git-worktree?workspace=${encodeURIComponent(workspace)}`, {
      headers: apiHeaders(token),
    });
    if (invalid.status !== 404) {
      throw new Error(`invalid git worktree workspace returned HTTP ${invalid.status}`);
    }

    if (probeCalled) {
      throw new Error("git worktree API called the app-server probe");
    }
  } finally {
    await closeServer(server);
    await rm(workspace, { recursive: true, force: true });
  }
  pass("dev server git worktree API is read-only and sanitized");
}

async function checkGitBranchSwitchApi() {
  const git = {
    isRepository: true,
    gitMetadataType: "directory",
    isLinkedWorktree: false,
    followsLinkedGitDir: false,
    headKind: "branch",
    branch: "feature/verify",
    commitShort: "dddddddddddd",
    hasRemotes: true,
    remoteCount: 1,
    localBranchCount: 2,
    returnedBranchCount: 2,
    branches: [
      { name: "feature/verify", current: true, commitShort: "dddddddddddd" },
      { name: "release/verify", current: false, commitShort: "eeeeeeeeeeee" },
    ],
    linkedWorktreeCount: 0,
    returnedLinkedWorktreeCount: 0,
    linkedWorktrees: [],
    statusAvailable: true,
    statusMode: "index-mtime-size",
    trackedFileCount: 1,
    checkedTrackedFileCount: 1,
    modifiedTrackedCount: 0,
    missingTrackedCount: 0,
    untrackedTopLevelCount: 0,
    statusTruncated: false,
    branchSwitchSafety: {
      hookFileCount: 0,
      filterConfigCount: 0,
      attributesFileCount: 0,
      configExecutionCount: 0,
      hooksPresent: false,
      filtersPresent: false,
      attributesPresent: false,
      configExecutionPresent: false,
      riskPresent: false,
      scanTruncated: false,
      warnings: [],
    },
    branchSwitchAvailable: false,
    commitActionsAvailable: false,
    warnings: [],
  };
  const calls = [];
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    gitWorktreeFn: async () => git,
    gitBranchSwitchEnabled: true,
    gitBranchSwitchFn: async (options) => {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        action: {
          type: "git-branch-switch",
          execution: "completed",
          branchSwitchExecuted: true,
          gitSubprocess: true,
          filesystemWrites: true,
          appServerTouched: false,
          reason: null,
        },
        target: {
          branch: "release/verify",
          current: false,
          commitShort: "eeeeeeeeeeee",
        },
        before: {
          branch: "feature/verify",
          headKind: "branch",
          commitShort: "dddddddddddd",
        },
        after: {
          branch: "release/verify",
          headKind: "branch",
          commitShort: "eeeeeeeeeeee",
        },
        status: {
          before: {
            statusAvailable: true,
            changedCount: 0,
            modifiedTrackedCount: 0,
            missingTrackedCount: 0,
            untrackedTopLevelCount: 0,
            statusTruncated: false,
          },
          after: {
            statusAvailable: true,
            changedCount: 0,
            modifiedTrackedCount: 0,
            missingTrackedCount: 0,
            untrackedTopLevelCount: 0,
            statusTruncated: false,
          },
        },
        safety: git.branchSwitchSafety,
        subprocess: {
          invoked: true,
          command: "git switch",
          exitCode: 0,
        },
      };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const token = await readUiSessionToken(baseUrl);
    const missingPreflight = await fetch(`${baseUrl}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        branch: "release/verify",
      }),
    });
    if (missingPreflight.status !== 400) {
      throw new Error(`git branch switch without preflight returned HTTP ${missingPreflight.status}`);
    }
    if (calls.length !== 0) {
      throw new Error("git branch switch without preflight executed the switch function");
    }

    const preflightResponse = await fetch(`${baseUrl}/api/git-branch-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        branch: "release/verify",
      }),
    });
    if (!preflightResponse.ok) {
      throw new Error(`git branch switch preflight returned HTTP ${preflightResponse.status}`);
    }
    const preflightPayload = await preflightResponse.json();
    if (preflightPayload.policy?.executionGateEnabled !== true) {
      throw new Error("git branch switch preflight did not expose the enabled execution gate");
    }
    assertActionPreflight(preflightPayload, "git-branch-switch", "default");

    const response = await fetch(`${baseUrl}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        branch: "release/verify",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (!response.ok) {
      throw new Error(`git branch switch returned HTTP ${response.status}`);
    }
    assertSanitizedGitBranchSwitch(await response.json(), preflightPayload.preflight.token);
    if (calls.length !== 1 || calls[0].branch !== "release/verify") {
      throw new Error("git branch switch did not call the switch function exactly once");
    }

    const replay = await fetch(`${baseUrl}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        branch: "release/verify",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (replay.status !== 409) {
      throw new Error(`git branch switch replay returned HTTP ${replay.status}`);
    }
    if (calls.length !== 1) {
      throw new Error("git branch switch replay executed the switch function");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server git branch switch consumes preflight before opt-in mutation");
}

