async function checkExecutionGateApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-extra"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/execution-gate`);
    if (withoutToken.status !== 403) {
      throw new Error(`execution gate API without token returned HTTP ${withoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/execution-gate`, {
      method: "POST",
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`execution gate POST returned HTTP ${wrongMethod.status}`);
    }

    const response = await fetch(`${baseUrl}/api/execution-gate?workspace=workspace-2`, {
      headers: apiHeaders(token),
    });
    if (!response.ok) {
      throw new Error(`execution gate API returned HTTP ${response.status}`);
    }
    assertSanitizedExecutionGate(await response.json());

    const invalid = await fetch(`${baseUrl}/api/execution-gate?workspace=/tmp/codex-app-port-verify`, {
      headers: apiHeaders(token),
    });
    if (invalid.status !== 404) {
      throw new Error(`invalid execution gate workspace returned HTTP ${invalid.status}`);
    }

    if (probeCalled) {
      throw new Error("execution gate API called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server execution gate is blocked without app-server traffic");
}

