async function checkMcpToolPreflightApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-extra"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/mcp-tool-preflight`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        server: "verify-private-mcp",
        tool: "verify-private-tool",
      }),
    });
    if (withoutToken.status !== 403) {
      throw new Error(`MCP tool preflight without token returned HTTP ${withoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/mcp-tool-preflight`, {
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`MCP tool preflight GET returned HTTP ${wrongMethod.status}`);
    }

    const args = JSON.stringify({
      path: "/tmp/codex-app-port-verify-extra/secret.txt",
      token: "sk-proj-verifysecret",
    });
    const response = await fetch(`${baseUrl}/api/mcp-tool-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        server: "verify-private-mcp",
        tool: "verify-private-tool",
        arguments: args,
      }),
    });
    if (!response.ok) {
      throw new Error(`MCP tool preflight returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    assertSanitizedMcpToolPreflight(payload, {
      argsLength: args.length,
    });
    const historyResponse = await fetch(`${baseUrl}/api/settings-integrations?workspace=workspace-2`, {
      headers: apiHeaders(token),
    });
    if (!historyResponse.ok) {
      throw new Error(`MCP tool preflight history returned HTTP ${historyResponse.status}`);
    }
    assertSanitizedIntegrationPreflightHistory(await historyResponse.json(), {
      type: "mcp-tool-preflight",
      method: "mcpServer/tool/call",
      token: payload.preflight.token,
      serverLength: "verify-private-mcp".length,
      toolLength: "verify-private-tool".length,
      argsLength: args.length,
      argKeys: 2,
    });

    const invalid = await fetch(`${baseUrl}/api/mcp-tool-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        server: "verify-private-mcp",
        tool: "   ",
        arguments: "Sensitive invalid args",
      }),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid MCP tool preflight returned HTTP ${invalid.status}`);
    }
    const invalidText = await invalid.text();
    if (invalidText.includes("verify-private-mcp") || invalidText.includes("Sensitive invalid args")) {
      throw new Error("invalid MCP tool preflight leaked name or arguments");
    }

    if (probeCalled) {
      throw new Error("MCP tool preflight called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server MCP tool preflight validates without tool invocation");
}

