async function checkPluginContentPreflightApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-extra"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/plugin-content-preflight`, {
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`plugin content preflight GET returned HTTP ${wrongMethod.status}`);
    }

    const target = "verify-private-plugin";
    const args = JSON.stringify({
      skill: "verify-private-plugin-skill",
      shareUrl: "https://private.example.test/share",
      token: "sk-proj-verifysecret",
    });
    const response = await fetch(`${baseUrl}/api/plugin-content-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        method: "plugin/skill/read",
        target,
        arguments: args,
      }),
    });
    if (!response.ok) {
      throw new Error(`plugin content preflight returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    assertSanitizedPluginContentPreflight(payload, {
      method: "plugin/skill/read",
      targetLength: target.length,
      argsLength: args.length,
      argKeys: 3,
    });

    const confirmResponse = await fetch(`${baseUrl}/api/action-preflight-confirm`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        actionType: "plugin-content-preflight",
        preflightToken: payload.preflight.token,
        method: "plugin/skill/read",
        target,
        arguments: args,
      }),
    });
    if (!confirmResponse.ok) {
      throw new Error(`plugin content confirmation returned HTTP ${confirmResponse.status}`);
    }
    const confirmationPayload = await confirmResponse.json();
    assertSanitizedActionPreflightConfirmation(
      confirmationPayload,
      "plugin-content-preflight",
      "workspace-2",
      payload.preflight.token,
    );
    if (
      confirmationPayload.action?.method !== "plugin/skill/read" ||
      confirmationPayload.policy?.pluginContentRead !== false ||
      confirmationPayload.policy?.pluginShareList !== false
    ) {
      throw new Error("plugin content confirmation did not preserve blocked policy metadata");
    }

    const historyResponse = await fetch(`${baseUrl}/api/settings-integrations?workspace=workspace-2`, {
      headers: apiHeaders(token),
    });
    if (!historyResponse.ok) {
      throw new Error(`plugin content history returned HTTP ${historyResponse.status}`);
    }
    const historyPayload = await historyResponse.json();
    assertSanitizedIntegrationPreflightHistory(historyPayload, {
      type: "plugin-content-preflight",
      method: "plugin/skill/read",
      category: "plugins-read",
      token: payload.preflight.token,
      targetLength: target.length,
      argsLength: args.length,
      argKeys: 3,
    });
    assertSanitizedIntegrationConfirmationHistory(historyPayload, {
      type: "plugin-content-preflight",
      method: "plugin/skill/read",
      category: "plugins-read",
      token: payload.preflight.token,
      targetLength: target.length,
      argsLength: args.length,
      argKeys: 3,
    });

    const shareResponse = await fetch(`${baseUrl}/api/plugin-content-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        method: "plugin/share/list",
        target,
        arguments: args,
      }),
    });
    if (!shareResponse.ok) {
      throw new Error(`plugin share-list preflight returned HTTP ${shareResponse.status}`);
    }
    assertSanitizedPluginContentPreflight(await shareResponse.json(), {
      method: "plugin/share/list",
      targetLength: target.length,
      argsLength: args.length,
      argKeys: 3,
    });

    const invalid = await fetch(`${baseUrl}/api/plugin-content-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        method: "plugin/read",
        target: "verify-private-plugin",
        arguments: "Sensitive invalid args",
      }),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid plugin content preflight returned HTTP ${invalid.status}`);
    }
    const invalidText = await invalid.text();
    if (invalidText.includes("verify-private-plugin") || invalidText.includes("Sensitive invalid args")) {
      throw new Error("invalid plugin content preflight leaked sensitive text");
    }

    if (probeCalled) {
      throw new Error("plugin content preflight called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server plugin content preflight blocks skill reads and share lists");
}

