async function checkTerminalCommandExecutionApi() {
  const actionAuditDir = await mkdtemp(join(tmpdir(), "codex-verify-terminal-command-audit-"));
  const actionAuditLogPath = join(actionAuditDir, "actions.jsonl");
  const calls = [];
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    terminalCommandEnabled: true,
    terminalCommandAllowlist: ["printf"],
    terminalCommandFn: async (options) => {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        initialize: {
          platformFamily: "unix",
          platformOs: "linux",
          codexHome: "/tmp/verify-private-home",
          userAgent: "verify-private-agent",
        },
        probes: {
          terminalCommandExec: {
            method: "command/exec",
            resultStatus: "completed",
            exitCode: 0,
            argvCount: options.argv.length,
            timeoutMs: 1000,
            sandboxPolicy: "readOnly",
            stdout: { charCount: 19, byteCount: 19, textReturned: true },
            stderr: { charCount: 11, byteCount: 11, textReturned: true },
            commandTextReturned: true,
            argvReturned: true,
            cwdReturned: true,
            outputTextReturned: true,
            processIdReturned: true,
            environmentReturned: true,
          },
        },
        notifications: {},
      };
    },
    actionAuditLog: createActionAuditLog({
      path: actionAuditLogPath,
      now: () => "2026-05-16T00:00:00.000Z",
    }),
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const token = await readUiSessionToken(baseUrl);
    const command = "printf privatecmdarg";
    const preflightResponse = await fetch(`${baseUrl}/api/terminal-command-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        command,
      }),
    });
    if (!preflightResponse.ok) {
      throw new Error(`terminal command execution preflight returned HTTP ${preflightResponse.status}`);
    }
    const preflightPayload = await preflightResponse.json();
    if (
      preflightPayload.policy?.executionGateEnabled !== true ||
      preflightPayload.command?.argvSupported !== true ||
      preflightPayload.command?.executableAllowed !== true ||
      Object.hasOwn(preflightPayload.command, "argv")
    ) {
      throw new Error("terminal command execution preflight did not enforce allowlisted argv mode");
    }

    const response = await fetch(`${baseUrl}/api/terminal-command`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        command,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (!response.ok) {
      throw new Error(`terminal command execution returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    assertSanitizedTerminalCommandExecution(payload, {
      token: preflightPayload.preflight.token,
      commandLength: command.length,
    });
    if (calls.length !== 1 || calls[0].argv.join(" ") !== command) {
      throw new Error("terminal command execution did not call the allowlisted argv runner");
    }

    const historyResponse = await fetch(`${baseUrl}/api/terminal-actions`, {
      headers: apiHeaders(token),
    });
    if (!historyResponse.ok) {
      throw new Error(`terminal command history returned HTTP ${historyResponse.status}`);
    }
    const historyPayload = await historyResponse.json();
    assertSanitizedTerminalCommandHistory(historyPayload, {
      commandLength: command.length,
      token: preflightPayload.preflight.token,
    });

    const replayResponse = await fetch(`${baseUrl}/api/terminal-command`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        command,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (replayResponse.status !== 409) {
      throw new Error(`terminal command replay returned HTTP ${replayResponse.status}`);
    }
    if ((await replayResponse.text()).includes(command)) {
      throw new Error("terminal command replay leaked command text");
    }

    const auditRecords = (await readFile(actionAuditLogPath, "utf8"))
      .trim()
      .split("\n")
      .map((line) => JSON.parse(line));
    if (
      auditRecords.length !== 1 ||
      auditRecords[0].event !== "terminal-command-recorded" ||
      auditRecords[0].action?.type !== "terminal-command" ||
      auditRecords[0].appServer?.commandTraffic !== true ||
      auditRecords[0].result?.stdoutReturned !== false
    ) {
      throw new Error("terminal command audit record did not preserve sanitized command metadata");
    }
    assertNoMarkers(JSON.stringify(auditRecords), [
      command,
      "printf",
      "privatecmdarg",
      preflightPayload.preflight.token,
      "/tmp/codex-app-port-verify",
      "/tmp/verify-private-home",
      "verify-private-agent",
      "\"textReturned\":true",
      "\"argvReturned\":true",
    ]);
  } finally {
    await closeServer(server);
    await rm(actionAuditDir, { recursive: true, force: true });
  }
  pass("dev server terminal command execution is opt-in, allowlisted, and sanitized");
}

