    const replay = await fetch(`${baseUrl}/api/thread-shell-command`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        thread: "abcd1234",
        command,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (replay.status !== 409) {
      throw new Error(`thread shell replay returned HTTP ${replay.status}`);
    }
    if (calls.filter((call) => call.method === "runThreadShellCommand").length !== 1) {
      throw new Error("thread shell replay executed again");
    }

    const auditRecords = (await readFile(actionAuditLogPath, "utf8"))
      .trim()
      .split("\n")
