async function checkFileActionPreflightApi() {
  let probeCalled = false;
  const content = "token=sk-proj-verifysecret\nSensitive file body";
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-extra"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/file-action-preflight`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        action: "writeFile",
        path: "src/secret.txt",
        content: "verify secret",
      }),
    });
    if (withoutToken.status !== 403) {
      throw new Error(`file action preflight without token returned HTTP ${withoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/file-action-preflight`, {
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`file action preflight GET returned HTTP ${wrongMethod.status}`);
    }

    const response = await fetch(`${baseUrl}/api/file-action-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
      }),
    });
    if (!response.ok) {
      throw new Error(`file action preflight returned HTTP ${response.status}`);
    }
    assertSanitizedFileActionPreflight(await response.json(), {
      contentLength: content.length,
    });

    const copyResponse = await fetch(`${baseUrl}/api/file-action-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        action: "copy",
        sourcePath: "src/input.txt",
        targetPath: "dist/output.txt",
      }),
    });
    if (!copyResponse.ok) {
      throw new Error(`file action copy preflight returned HTTP ${copyResponse.status}`);
    }
    const copyPayload = await copyResponse.json();
    if (
      copyPayload.action?.method !== "fs/copy" ||
      copyPayload.source?.basename !== "input.txt" ||
      copyPayload.target?.basename !== "output.txt" ||
      JSON.stringify(copyPayload).includes("src/input.txt")
    ) {
      throw new Error("file action copy preflight did not preserve path-free metadata");
    }

    const invalid = await fetch(`${baseUrl}/api/file-action-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        action: "writeFile",
        path: "/tmp/codex-app-port-verify-extra/secret.txt",
        content: "Sensitive invalid content",
      }),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid file action preflight returned HTTP ${invalid.status}`);
    }
    const invalidText = await invalid.text();
    if (
      invalidText.includes("/tmp/codex-app-port-verify-extra") ||
      invalidText.includes("Sensitive invalid content")
    ) {
      throw new Error("invalid file action preflight leaked path or content");
    }

    if (probeCalled) {
      throw new Error("file action preflight called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }

  const disabledCalls = [];
  const disabledServer = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-two"],
    fileActionFn: async (options) => {
      disabledCalls.push(options);
      return {};
    },
  });
  const disabledPort = await listenWithFallback(disabledServer, {
    host: "127.0.0.1",
    port: 0,
  });
  const disabledBaseUrl = `http://127.0.0.1:${disabledPort}`;
  try {
    const token = await readUiSessionToken(disabledBaseUrl);
    const preflight = await fetch(`${disabledBaseUrl}/api/file-action-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
      }),
    });
    if (!preflight.ok) {
      throw new Error(`disabled file action preflight returned HTTP ${preflight.status}`);
    }
    const preflightPayload = await preflight.json();
    if (preflightPayload.policy?.executionGateEnabled !== false) {
      throw new Error("disabled file action preflight unexpectedly enabled execution");
    }
    const blocked = await fetch(`${disabledBaseUrl}/api/file-action`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (blocked.status !== 403) {
      throw new Error(`disabled file action returned HTTP ${blocked.status}`);
    }
    const blockedText = await blocked.text();
    if (blockedText.includes("src/secret.txt") || blockedText.includes("sk-proj-verifysecret")) {
      throw new Error("disabled file action leaked path or content");
    }
    if (disabledCalls.length !== 0) {
      throw new Error("disabled file action called the action function");
    }
  } finally {
    await closeServer(disabledServer);
  }

  const calls = [];
  const actionAuditDir = await mkdtemp(join(tmpdir(), "codex-app-port-verify-file-audit-"));
  const actionAuditLogPath = join(actionAuditDir, "actions.jsonl");
  const enabledServer = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-two"],
    fileActionEnabled: true,
    actionAuditLog: createActionAuditLog({
      path: actionAuditLogPath,
      now: () => "2026-05-16T00:00:00.000Z",
    }),
    fileActionFn: async (options) => {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        action: {
          type: "file-action",
          fileAction: options.action,
          method: "fs/writeFile",
          execution: "completed",
          filesystemWrites: true,
          appServerTouched: false,
          reason: null,
        },
        target: {
          basename: "secret.txt",
          depth: 2,
          pathReturned: false,
        },
        source: null,
        content: {
          present: true,
          charCount: content.length,
          lineCount: 2,
          textReturned: false,
        },
        filesystem: {
          wroteFile: true,
          removed: false,
          copied: false,
          createdDirectory: false,
        },
      };
    },
  });
  const enabledPort = await listenWithFallback(enabledServer, {
    host: "127.0.0.1",
    port: 0,
  });
  const enabledBaseUrl = `http://127.0.0.1:${enabledPort}`;
  try {
    const token = await readUiSessionToken(enabledBaseUrl);
    const missingPreflight = await fetch(`${enabledBaseUrl}/api/file-action`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
      }),
    });
    if (missingPreflight.status !== 400) {
      throw new Error(`file action without preflight returned HTTP ${missingPreflight.status}`);
    }
    if ((await missingPreflight.text()).includes("src/secret.txt")) {
      throw new Error("file action without preflight leaked path");
    }
    if (calls.length !== 0) {
      throw new Error("file action without preflight called the action function");
    }

    const preflight = await fetch(`${enabledBaseUrl}/api/file-action-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
      }),
    });
    if (!preflight.ok) {
      throw new Error(`enabled file action preflight returned HTTP ${preflight.status}`);
    }
    const preflightPayload = await preflight.json();
    if (preflightPayload.policy?.executionGateEnabled !== true) {
      throw new Error("file action preflight did not expose the enabled execution gate");
    }

    const actionResponse = await fetch(`${enabledBaseUrl}/api/file-action`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (!actionResponse.ok) {
      throw new Error(`file action returned HTTP ${actionResponse.status}`);
    }
    assertSanitizedFileAction(await actionResponse.json(), {
      consumedPreflightToken: preflightPayload.preflight.token,
      contentLength: content.length,
    });
    const historyResponse = await fetch(`${enabledBaseUrl}/api/terminal-actions?workspace=workspace-2`, {
      headers: apiHeaders(token),
    });
    if (!historyResponse.ok) {
      throw new Error(`file action history returned HTTP ${historyResponse.status}`);
    }
    assertSanitizedFileActionHistory(await historyResponse.json(), {
      consumedPreflightToken: preflightPayload.preflight.token,
      contentLength: content.length,
    });
    if (
      calls.length !== 1 ||
      calls[0].workspace.id !== "workspace-2" ||
      calls[0].path !== "src/secret.txt" ||
      calls[0].content !== content
    ) {
      throw new Error("file action did not call the action function exactly once");
    }

    const replay = await fetch(`${enabledBaseUrl}/api/file-action`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        action: "writeFile",
        path: "src/secret.txt",
        content,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (replay.status !== 409) {
      throw new Error(`file action replay returned HTTP ${replay.status}`);
    }
    if (calls.length !== 1) {
      throw new Error("file action replay executed the action function");
    }

    const auditRecords = (await readFile(actionAuditLogPath, "utf8"))
      .trim()
      .split("\n")
      .map((line) => JSON.parse(line));
    assertSanitizedFileActionAudit(auditRecords, {
      consumedPreflightToken: preflightPayload.preflight.token,
      contentLength: content.length,
    });
  } finally {
    await closeServer(enabledServer);
    await rm(actionAuditDir, { recursive: true, force: true });
  }

  pass("dev server file action preflight and opt-in execution consume one-time tokens");
}

async function checkTurnStartGuardApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/turn-start`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        thread: "abcd1234",
        prompt: "Sensitive start prompt without token",
      }),
    });
    if (withoutToken.status !== 403) {
      throw new Error(`turn start API without token returned HTTP ${withoutToken.status}`);
    }
    const sessionsWithoutToken = await fetch(`${baseUrl}/api/turn-sessions`);
    if (sessionsWithoutToken.status !== 403) {
      throw new Error(`turn sessions API without token returned HTTP ${sessionsWithoutToken.status}`);
    }
    const decisionsWithoutToken = await fetch(`${baseUrl}/api/approval-decisions`);
    if (decisionsWithoutToken.status !== 403) {
      throw new Error(`approval decisions API without token returned HTTP ${decisionsWithoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/turn-start`, {
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`turn start GET returned HTTP ${wrongMethod.status}`);
    }

    const response = await fetch(`${baseUrl}/api/turn-start`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "default",
        thread: "abcd1234",
        prompt: "Sensitive user prompt that must not be echoed",
      }),
    });
    if (response.status !== 403) {
      throw new Error(`turn start API returned HTTP ${response.status}`);
    }
    assertSanitizedTurnStartGuard(await response.json());

    const invalid = await fetch(`${baseUrl}/api/turn-start`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        thread: "../abcd",
        prompt: "Sensitive invalid start prompt",
      }),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid turn start returned HTTP ${invalid.status}`);
    }
    if ((await invalid.text()).includes("Sensitive invalid start prompt")) {
      throw new Error("invalid turn start response leaked prompt content");
    }

    if (probeCalled) {
      throw new Error("turn start guard called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server turn start guard refuses execution without model traffic");
}

