function assertSanitizedApprovalDecision(payload) {
  if (!payload.ok) {
    throw new Error("approval decision payload is not ok");
  }
  const serialized = JSON.stringify(payload);
  for (const marker of [
    "Sensitive opt-in prompt",
    "/tmp/codex-app-port-verify",
    "/tmp/verify-private-home",
    "codexHome",
    "userAgent",
    "secret.txt",
  ]) {
    if (serialized.includes(marker)) {
      throw new Error(`approval decision payload leaked ${marker}`);
    }
  }
  if (
    payload.appServer?.touched !== false ||
    payload.appServer?.decisionForwarding !== false ||
    payload.policy?.forwardedToAppServer !== false ||
    payload.policy?.approveDecisionsAccepted !== false ||
    payload.policy?.browserDecisionIntake !== "deny-only-recorded" ||
    payload.policy?.replayProtectionImplemented !== true ||
    payload.policy?.replayProtectionScope !==
      "process-local-and-audit-log-single-decision-per-request" ||
    payload.policy?.approvalDetailsReturned !== false ||
    payload.policy?.rawCommandTextReturned !== false ||
    payload.policy?.decisionTokenRequired !== true ||
    payload.policy?.decisionTokenLogged !== false ||
    payload.policy?.decisionHistoryReturned !== true ||
    payload.policy?.decisionHistoryTokensReturned !== false ||
    payload.policy?.decisionHistoryRequestKeysReturned !== false ||
    payload.policy?.auditLogPersistent !== true ||
    payload.policy?.auditLogPathReturned !== false
  ) {
    throw new Error("approval decision payload did not stay fail-closed");
  }
  assertSanitizedApprovalLifecyclePolicy(payload.policy);
  assertApprovalDecisionScope(payload.policy, { forwarded: false, acceptOnce: false });
  if (
    payload.decision?.browserDecision?.decision !== "decline" ||
    payload.decision?.browserDecision?.forwarded !== false ||
    payload.decision?.browserDecision?.auditLogged !== true ||
    payload.decision?.request?.decisionToken !== undefined ||
    payload.decision?.request?.command?.charCount !== 32
  ) {
    throw new Error("approval decision payload did not preserve sanitized decision metadata");
  }
}

