function assertSanitizedApprovalDecisionBatch(payload, decisions) {
  if (!payload.ok) {
    throw new Error("approval decision batch payload is not ok");
  }
  const serialized = JSON.stringify(payload);
  for (const marker of [
    "Sensitive batch prompt",
    "/tmp/codex-app-port-verify",
    "/tmp/verify-private-home",
    "codexHome",
    "userAgent",
    "secret.txt",
    "verify-secret-token",
    decisions[0]?.decisionToken,
    decisions[1]?.decisionToken,
  ]) {
    if (marker && serialized.includes(marker)) {
      throw new Error(`approval decision batch payload leaked ${marker}`);
    }
  }
  if (
    payload.appServer?.touched !== false ||
    payload.appServer?.decisionForwarding !== false ||
    payload.approvalCount !== 2 ||
    payload.decisions?.length !== 2 ||
    payload.policy?.batchDecisionsAccepted !== true ||
    payload.policy?.decisionBatchLimit !== MAX_APPROVAL_DECISION_BATCH ||
    payload.policy?.forwardedToAppServer !== false ||
    payload.policy?.decisionTokenRequired !== true ||
    payload.policy?.decisionTokenLogged !== false ||
    payload.policy?.decisionHistoryReturned !== true
  ) {
    throw new Error("approval decision batch payload did not stay fail-closed");
  }
  assertSanitizedApprovalLifecyclePolicy(payload.policy);
  assertApprovalDecisionScope(payload.policy, { forwarded: false, acceptOnce: false });
  for (const decision of payload.decisions) {
    if (
      decision?.browserDecision?.decision !== "decline" ||
      decision?.browserDecision?.forwarded !== false ||
      decision?.request?.decisionToken !== undefined
    ) {
      throw new Error("approval decision batch item did not preserve sanitized metadata");
    }
  }
}

