function assertSanitizedIntegrationActions(
  payload,
  { readMethodCount, localGateCount, enabledMutationGateCount, historyCount, appServerTouched },
) {
  const actions = payload.integrationLifecycle?.integrationActions;
  const scope = payload.integrationScope ?? {};
  const accountActionCount = [
    scope.accountLoginEnabled,
    scope.accountLoginCancelEnabled,
    scope.accountLogoutEnabled,
  ].filter(Boolean).length;
  const settingsActionCount = [
    scope.configBatchWriteEnabled,
    scope.configValueWriteEnabled,
    scope.environmentAddEnabled,
    scope.experimentalFeatureSetEnabled,
  ].filter(Boolean).length;
  const mcpActionCount = [
    scope.mcpOauthLoginEnabled,
    scope.mcpServerReloadEnabled,
    scope.mcpToolInvocationEnabled,
    scope.mcpResourceReadEnabled,
  ].filter(Boolean).length;
  const pluginActionCount = [
    scope.pluginReadEnabled,
    scope.pluginShareCheckoutEnabled,
    scope.pluginUninstallEnabled,
    scope.pluginContentReadEnabled,
    scope.pluginShareListEnabled,
  ].filter(Boolean).length;
  const skillsActionCount = scope.skillsConfigWriteEnabled ? 1 : 0;
  const executableActionCount =
    accountActionCount +
    settingsActionCount +
    mcpActionCount +
    pluginActionCount +
    skillsActionCount;
  const preflightOnlyGateCount = Math.max(0, localGateCount - executableActionCount);
  const expectedState =
    executableActionCount > 0
      ? "actionable"
      : preflightOnlyGateCount > 0
        ? "preflight-only"
        : historyCount > 0
          ? "history-only"
          : "blocked";
  if (
    actions?.returned !== true ||
    actions?.state !== expectedState ||
    actions?.readMethodCount !== readMethodCount ||
    actions?.localGateCount !== localGateCount ||
    actions?.preflightOnlyGateCount !== preflightOnlyGateCount ||
    actions?.executableActionCount !== executableActionCount ||
    actions?.enabledMutationGateCount !== enabledMutationGateCount ||
    actions?.blockedMutationMethodCount !== blockedIntegrationMutationMethods().length ||
    actions?.accountActionCount !== accountActionCount ||
    actions?.settingsActionCount !== settingsActionCount ||
    actions?.mcpActionCount !== mcpActionCount ||
    actions?.pluginActionCount !== pluginActionCount ||
    actions?.skillsActionCount !== skillsActionCount ||
    actions?.accountActionsEnabled !== (accountActionCount > 0) ||
    actions?.settingsActionsEnabled !== (settingsActionCount > 0) ||
    actions?.mcpActionsEnabled !== (mcpActionCount > 0) ||
    actions?.pluginActionsEnabled !== (pluginActionCount > 0) ||
    actions?.skillsActionsEnabled !== (skillsActionCount > 0) ||
    actions?.resourceReadEnabled !== Boolean(scope.mcpResourceReadEnabled) ||
    actions?.appServerInventoryVisible !== appServerTouched ||
    actions?.historyCount !== historyCount ||
    actions?.requiresExplicitEnablement !== true ||
    actions?.requiresPreflightForMutations !== true ||
    actions?.requestScopedOnly !== true ||
    actions?.browserMethodCallsAccepted !== false ||
    actions?.preflightTokensReturned !== false ||
    actions?.namesReturned !== false ||
    actions?.targetsReturned !== false ||
    actions?.argumentTextReturned !== false ||
    actions?.resourceContentReturned !== false ||
    actions?.skillContentsReturned !== false ||
    actions?.urlsReturned !== false ||
    actions?.pathsReturned !== false ||
    actions?.secretsReturned !== false ||
    actions?.rawPayloadsReturned !== false ||
    actions?.appServerPayloadReturned !== false
  ) {
    throw new Error("integration action summary did not preserve sanitized gate metadata");
  }
}

